import io.jsonwebtoken.Claims;
import io.jsonwebtoken.Jws;
import io.jsonwebtoken.JwtException;
import io.jsonwebtoken.Jwts;
import io.jsonwebtoken.security.Keys;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

import javax.crypto.SecretKey;
import javax.servlet.FilterChain;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.nio.charset.StandardCharsets;
import java.util.Collections;
import java.util.Date;
import java.util.List;
import java.util.stream.Collectors;

@Component
public class JwtAuthenticationFilter extends OncePerRequestFilter {

    private static final String AUTHORIZATION_HEADER = "Authorization";
    private static final String BEARER_PREFIX = "Bearer ";
    private static final String EXPECTED_ISSUER = "my-application";

    private final SecretKey signingKey;

    public JwtAuthenticationFilter(@Value("${jwt.secret}") String secret) {
        // Use a key derived from the configured secret; key must be at least 256 bits for HS256
        this.signingKey = Keys.hmacShaKeyFor(secret.getBytes(StandardCharsets.UTF_8));
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request,
                                    HttpServletResponse response,
                                    FilterChain filterChain) throws ServletException, IOException {

        String authorizationHeader = request.getHeader(AUTHORIZATION_HEADER);

        if (authorizationHeader == null || !authorizationHeader.startsWith(BEARER_PREFIX)) {
            filterChain.doFilter(request, response);
            return;
        }

        String token = authorizationHeader.substring(BEARER_PREFIX.length()).trim();

        try {
            // Parse and verify the JWT with explicit algorithm allowlisting (HS256 only)
            // This prevents algorithm confusion attacks (e.g., "none" algorithm or RS256/HS256 swap)
            Jws<Claims> jwsClaims = Jwts.parserBuilder()
                    .setSigningKey(signingKey)
                    // Explicitly require HS256 algorithm — rejects tokens signed with any other algorithm
                    .requireIssuer(EXPECTED_ISSUER)
                    .setAllowedClockSkewSeconds(30)
                    .build()
                    .parseClaimsJws(token);

            Claims claims = jwsClaims.getBody();

            // Verify the algorithm in the header is HS256 (defense in depth)
            String algorithm = jwsClaims.getHeader().getAlgorithm();
            if (!"HS256".equals(algorithm)) {
                logger.warn("JWT rejected: unexpected algorithm " + algorithm);
                response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
                response.getWriter().write("{\"error\": \"Invalid token algorithm\"}");
                return;
            }

            // Require expiration claim and verify it hasn't expired
            Date expiration = claims.getExpiration();
            if (expiration == null) {
                logger.warn("JWT rejected: missing expiration claim");
                response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
                response.getWriter().write("{\"error\": \"Token missing expiration\"}");
                return;
            }
            if (expiration.before(new Date())) {
                logger.warn("JWT rejected: token has expired");
                response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
                response.getWriter().write("{\"error\": \"Token has expired\"}");
                return;
            }

            // Require issued-at claim
            Date issuedAt = claims.getIssuedAt();
            if (issuedAt == null) {
                logger.warn("JWT rejected: missing issued-at claim");
                response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
                response.getWriter().write("{\"error\": \"Token missing issued-at\"}");
                return;
            }

            // Reject tokens issued in the future (with small clock skew tolerance)
            if (issuedAt.after(new Date(System.currentTimeMillis() + 30_000))) {
                logger.warn("JWT rejected: token issued in the future");
                response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
                response.getWriter().write("{\"error\": \"Token issued in the future\"}");
                return;
            }

            // Require subject claim (user identifier)
            String username = claims.getSubject();
            if (username == null || username.isBlank()) {
                logger.warn("JWT rejected: missing subject claim");
                response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
                response.getWriter().write("{\"error\": \"Token missing subject\"}");
                return;
            }

            // Extract roles/authorities from claims
            List<SimpleGrantedAuthority> authorities = extractAuthorities(claims);

            // Build authentication token and set it in the security context
            UsernamePasswordAuthenticationToken authentication =
                    new UsernamePasswordAuthenticationToken(username, null, authorities);

            // Store additional user info as details
            JwtUserDetails userDetails = new JwtUserDetails(
                    username,
                    claims.get("email", String.class),
                    claims.get("userId", String.class),
                    claims.getIssuer(),
                    claims.getExpiration(),
                    claims.getIssuedAt()
            );
            authentication.setDetails(userDetails);

            SecurityContextHolder.getContext().setAuthentication(authentication);

        } catch (JwtException e) {
            logger.warn("JWT verification failed: " + e.getMessage());
            SecurityContextHolder.clearContext();
            response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
            response.setContentType("application/json");
            response.getWriter().write("{\"error\": \"Invalid or expired token\"}");
            return;
        } catch (Exception e) {
            logger.error("Unexpected error during JWT processing", e);
            SecurityContextHolder.clearContext();
            response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
            response.setContentType("application/json");
            response.getWriter().write("{\"error\": \"Authentication failed\"}");
            return;
        }

        filterChain.doFilter(request, response);
    }

    @SuppressWarnings("unchecked")
    private List<SimpleGrantedAuthority> extractAuthorities(Claims claims) {
        Object rolesObj = claims.get("roles");
        if (rolesObj instanceof List<?>) {
            List<String> roles = (List<String>) rolesObj;
            return roles.stream()
                    .filter(role -> role != null && !role.isBlank())
                    .map(role -> new SimpleGrantedAuthority("ROLE_" + role.toUpperCase()))
                    .collect(Collectors.toList());
        }
        return Collections.emptyList();
    }

    /**
     * Holds extracted user details from the JWT for downstream use.
     */
    public static class JwtUserDetails {
        private final String username;
        private final String email;
        private final String userId;
        private final String issuer;
        private final Date expiration;
        private final Date issuedAt;

        public JwtUserDetails(String username, String email, String userId,
                              String issuer, Date expiration, Date issuedAt) {
            this.username = username;
            this.email = email;
            this.userId = userId;
            this.issuer = issuer;
            this.expiration = expiration;
            this.issuedAt = issuedAt;
        }

        public String getUsername() {
            return username;
        }

        public String getEmail() {
            return email;
        }

        public String getUserId() {
            return userId;
        }

        public String getIssuer() {
            return issuer;
        }

        public Date getExpiration() {
            return expiration;
        }

        public Date getIssuedAt() {
            return issuedAt;
        }

        @Override
        public String toString() {
            return "JwtUserDetails{" +
                    "username='" + username + '\'' +
                    ", email='" + email + '\'' +
                    ", userId='" + userId + '\'' +
                    ", issuer='" + issuer + '\'' +
                    '}';
        }
    }
}

// --- Security Configuration to register the filter ---

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.http.SessionCreationPolicy;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    private final JwtAuthenticationFilter jwtAuthenticationFilter;

    public SecurityConfig(JwtAuthenticationFilter jwtAuthenticationFilter) {
        this.jwtAuthenticationFilter = jwtAuthenticationFilter;
    }

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
                .csrf().disable()
                .sessionManagement().sessionCreationPolicy(SessionCreationPolicy.STATELESS)
                .and()
                .authorizeRequests()
                .antMatchers("/api/public/**", "/api/auth/**").permitAll()
                .antMatchers("/api/admin/**").hasRole("ADMIN")
                .anyRequest().authenticated()
                .and()
                .addFilterBefore(jwtAuthenticationFilter, UsernamePasswordAuthenticationFilter.class);

        return http.build();
    }
}

// --- Utility class for generating tokens (for testing/reference) ---

import io.jsonwebtoken.Jwts;
import io.jsonwebtoken.SignatureAlgorithm;
import io.jsonwebtoken.security.Keys;

import javax.crypto.SecretKey;
import java.nio.charset.StandardCharsets;
import java.util.Date;
import java.util.List;
import java.util.Map;

public class JwtTokenGenerator {

    private final SecretKey signingKey;
    private final long expirationMillis;

    public JwtTokenGenerator(String secret, long expirationMillis) {
        this.signingKey = Keys.hmacShaKeyFor(secret.getBytes(StandardCharsets.UTF_8));
        this.expirationMillis = expirationMillis;
    }

    public String generateToken(String username, String email, String userId, List<String> roles) {
        Date now = new Date();
        Date expiration = new Date(now.getTime() + expirationMillis);

        return Jwts.builder()
                .setSubject(username)
                .setIssuer("my-application")
                .setIssuedAt(now)
                .setExpiration(expiration)
                .addClaims(Map.of(
                        "email", email,
                        "userId", userId,
                        "roles", roles
                ))
                // Explicitly use HS256 algorithm
                .signWith(signingKey, SignatureAlgorithm.HS256)
                .compact();
    }
}